/**
 * @summary Get the full planning for a month (all employees × all days)
 */
export const GetMonthPlanningParams = zod.object({
  year: zod.coerce.number(),
  month: zod.coerce.number(),
});

export const GetMonthPlanningResponse = zod.object({
  year: zod.number(),
  month: zod.number(),
  status: zod.string().describe("draft | confirmed"),
  entries: zod.array(
    zod.object({
      id: zod.number(),
      employeeId: zod.number(),
      date: zod.string(),
      shiftCode: zod.string().nullish(),
      deskCode: zod
        .string()
        .nullish()
        .describe("Randomly assigned shared desk for onsite days"),
      isPermanence: zod.boolean(),
      permanenceLevel: zod.number().nullish(),
      isLocked: zod.boolean().describe("True when manually set or confirmed"),
      requestedOff: zod.boolean(),
      notes: zod.string().nullish(),
      isFromPrevMonth: zod
        .boolean()
        .describe(
          "True for entries fetched from the previous month's plan (overflow display only — excluded from this month's hour totals)",
        ),
    }),
  ),
  violations: zod.array(
    zod.object({
      date: zod.string(),
      type: zod
        .string()
        .describe(
          "missing_spoc | missing_management | missing_perma1 | missing_perma2 | desk_overflow | prm_exceeded | homework_limit | insufficient_onsite | role_gap",
        ),
      message: zod.string(),
      employeeId: zod.number().nullish(),
    }),
  ),
  generatedAt: zod.coerce.date().nullish(),
  negativeBalanceEmployees: zod
    .array(
      zod.object({
        employeeId: zod.number(),
        name: zod.string(),
      }),
    )
    .nullish()
    .describe(
      "Populated after confirmation — employees whose holiday balance went negative",
    ),
});

